def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        root = etree.fromstring(xml_data)

        # Use XPath to find student with matching username and password
        xpath_query = f"//student[username='{username}' and password='{password}']"
        student_nodes = root.xpath(xpath_query)

        if not student_nodes:
            return None

        student = student_nodes[0]
        result = {}

        for child in student:
            result[child.tag] = child.text

        return result

    except (etree.XMLSyntaxError, etree.XPathEvalError):
        return None

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    import re

    # Validate domain format
    domain_pattern = r'^[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?)*$'
    if not re.match(domain_pattern, domain):
        return f'https://{domain}'

    # Check if subdomain_prefix is empty or None
    if not subdomain_prefix or not subdomain_prefix.strip():
        return f'https://{domain}'

    # Validate subdomain_prefix format - only allow alphanumeric, hyphens, and dots
    # Each part separated by dots must be valid
    subdomain_pattern = r'^[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?)*$'

    if not re.match(subdomain_pattern, subdomain_prefix.strip()):
        return f'https://{domain}'

    # Additional validation: ensure no part starts or ends with hyphen
    parts = subdomain_prefix.strip().split('.')
    for part in parts:
        if not part or part.startswith('-') or part.endswith('-') or len(part) > 63:
            return f'https://{domain}'

    return f'https://{subdomain_prefix.strip()}.{domain}'

